#define THREADS_PER_BLOCK 256

__kernel void kernel_compute_cost(
    __global const Point_Struct *p,
    __global const float *coord,
    __global float *work_mem,
    __global const int *center_table,
    __global char *switch_membership,
    local float *local_coord,
    const int num,
    const int dim,
    const long x,
    const int K)
{
    int tid = get_global_id(0);

    if (tid < num) {
        float *lower = &work_mem[tid * (K + 1)];

        float x_cost = 0.0f;
        for (int i = 0; i < dim; i++) {
            float tmp = coord[i * num + tid] - coord[i * num + x];
            x_cost += tmp * tmp;
        }
        x_cost *= p[tid].weight;

        if (x_cost < p[tid].cost) {
            switch_membership[tid] = 1;
            lower[K] += x_cost - p[tid].cost;
        } else {
            int assign_idx = (int)p[tid].assign;
            int center_idx = center_table[assign_idx];
            lower[center_idx] += p[tid].cost - x_cost;
        }
    }
}
